import{_ as o,o as r,c as i,ae as a}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"AGENTS 与 Provider 扩展设计","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-03-26-agents-and-provider-expansion-design.zh-CN.md","filePath":"superpowers/specs/2026-03-26-agents-and-provider-expansion-design.zh-CN.md"}'),d={name:"superpowers/specs/2026-03-26-agents-and-provider-expansion-design.zh-CN.md"};function t(n,e,l,c,s,p){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="agents-与-provider-扩展设计" tabindex="-1">AGENTS 与 Provider 扩展设计 <a class="header-anchor" href="#agents-与-provider-扩展设计" aria-label="Permalink to &quot;AGENTS 与 Provider 扩展设计&quot;">​</a></h1><p><strong>日期：</strong> 2026-03-26</p><h2 id="范围" tabindex="-1">范围 <a class="header-anchor" href="#范围" aria-label="Permalink to &quot;范围&quot;">​</a></h2><p>本设计覆盖 Notemd 中三项相互关联的改动：</p><ol><li>在不重写 <code>GEMINI.md</code> 的前提下，新增项目级 <code>AGENTS.md</code>，作为 Codex/agent 工作流的执行权威。</li><li>为 <code>Doubao</code> 预设增加前端校验提示，当模型字段看起来仍是未设置的 Ark endpoint 占位值时，给用户明确反馈。</li><li>扩展集中式 LLM provider registry，新增 <code>Baidu Qianfan</code> 与 <code>SiliconFlow</code>，并补齐 runtime 支持、API 连接测试、文档与回归测试。</li></ol><p>之所以把这三项合并，是因为它们都在提升 agent/operator 的可靠性：一项作用于仓库工作流层，一项作用于 provider UX 层，一项作用于 provider 覆盖面。</p><h2 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h2><p>provider 架构应继续使用 <code>src/llmProviders.ts</code> 作为 provider 元数据的单一事实源。新增 provider 必须表现为 registry 定义，并沿着 <code>src/llmUtils.ts</code> 中 transport-driven 的 dispatch 路径流动，而不是继续增加 provider-name 分支。</p><p>provider 校验应实现为一个小型纯函数 helper，向 UI 消费方返回 warning。设置页可以渲染这些 warning，并在 provider 配置显然不完整时阻止 connection test。这样可以让校验逻辑保持可测试、可复用，而不是埋在脆弱的 UI 特判里。</p><p>新的 <code>AGENTS.md</code> 应作为仓库本地文档，明确表达 Notemd 的 build、verification、documentation、release 和 asset-upload 工作流。它必须显式写清：GitHub release 除了 <code>main.js</code>、<code>manifest.json</code>、<code>styles.css</code> 外，还必须上传 <code>README.md</code>。</p><h2 id="组件" tabindex="-1">组件 <a class="header-anchor" href="#组件" aria-label="Permalink to &quot;组件&quot;">​</a></h2><h3 id="_1-仓库指南" tabindex="-1">1. 仓库指南 <a class="header-anchor" href="#_1-仓库指南" aria-label="Permalink to &quot;1. 仓库指南&quot;">​</a></h3><ul><li>在仓库根目录创建 <code>AGENTS.md</code>。</li><li>保持 <code>GEMINI.md</code> 不变。</li><li>内容应覆盖项目概览、关键文件、build/test 命令、release workflow、文档同步规则、provider 扩展规则和 Git 安全规则。</li></ul><h3 id="_2-provider-校验" tabindex="-1">2. Provider 校验 <a class="header-anchor" href="#_2-provider-校验" aria-label="Permalink to &quot;2. Provider 校验&quot;">​</a></h3><ul><li>在 provider registry 附近新增一个小型校验 helper。</li><li>检测 <code>Doubao</code> 是否仍使用占位 endpoint model，或配置值是否看起来不像有效的 Ark endpoint ID。</li><li>在用户运行任务或连接测试之前，于设置页中展示 warning。</li></ul><h3 id="_3-provider-扩展" tabindex="-1">3. Provider 扩展 <a class="header-anchor" href="#_3-provider-扩展" aria-label="Permalink to &quot;3. Provider 扩展&quot;">​</a></h3><ul><li>将 <code>Baidu Qianfan</code> 与 <code>SiliconFlow</code> 新增到 registry 中。</li><li>保持它们继续走现有的 <code>openai-compatible</code> transport。</li><li>设置 API-test 元数据，确保 connection test 针对的是用户实际配置的 model。</li><li>同步更新 <code>README.md</code> 与 <code>README_zh.md</code>。</li></ul><h2 id="错误处理" tabindex="-1">错误处理 <a class="header-anchor" href="#错误处理" aria-label="Permalink to &quot;错误处理&quot;">​</a></h2><p>连接测试路径应继续沿用当前 runtime/API 错误处理行为。新的 provider-validation 层只处理明显不完整的本地配置，并生成面向用户的 warning；它不应尝试猜测或自动改写 provider model。</p><p>对于 <code>Doubao</code>，UX 的目标应是提示用户配置有效的 Ark endpoint，同时保留 provider 侧未来更改命名方式的空间。Warning 比破坏性归一化更安全。</p><h2 id="测试策略" tabindex="-1">测试策略 <a class="header-anchor" href="#测试策略" aria-label="Permalink to &quot;测试策略&quot;">​</a></h2><ul><li>为 provider validation warning 新增单元测试。</li><li>扩展 provider registry 测试，断言 <code>Baidu Qianfan</code> 与 <code>SiliconFlow</code> 存在。</li><li>扩展 provider runtime/API 测试，断言两者都走 openai-compatible runtime，并使用 chat-first API probing。</li><li>实现完成后重新运行完整 build 与 Jest 套件。</li></ul><h2 id="评审说明" tabindex="-1">评审说明 <a class="header-anchor" href="#评审说明" aria-label="Permalink to &quot;评审说明&quot;">​</a></h2><p>本次未使用专门的 spec-review 子代理，因为当前会话没有用户明确授权进行子代理委派。本设计已依据仓库当前 provider 架构与 release workflow 进行自审。</p>',24)])])}const m=o(d,[["render",t]]);export{u as __pageData,m as default};
